form:Form.form:Scripts:
		
function Validar_porc(me)
{
		var porc = 0;
		for (i = 0; i < Ctrl("MAIN_GRID").TotalRowsCount(); i++)
 		{   
 				porc = porc + str2number(Ctrl("MAIN_GRID").GetCellXValue("n_porcentaje", i));
 		}

 		if (porc != 100)
 		{
 				me.SetError('Los porcentajes deben sumar 100%');
 				return false;
 		}
 		return true;
}
